```js
// Log heap every 30s — watch for steady climb
setInterval(() => {
  const { heapUsed, heapTotal } = process.memoryUsage();
  console.log(`Heap: ${Math.round(heapUsed/1e6)}MB / ${Math.round(heapTotal/1e6)}MB`);
}, 30_000).unref(); // .unref() so it doesn't block exit
```

